var e=[{id:`L2_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`그래서, 어디까지 얘기했더라.`,JPN:`それで、どこまで話したんだったか。`,ENG:`Anyway, where was I?`,TWN:`對了，我說到哪裡了呢？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`......그래. 땅에 부딪치기 직전에 간신히 오메르타를 불러냈어.`,JPN:`……そうだ。落とされて地面にぶつかる直前に、なんとかオメルタを呼び出した。`,ENG:`Oh, right. I barely managed to summon Omerta right before we hit the ground.`,TWN:`……哦，在墜落到地面前，好不容易叫來了奧梅爾塔。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`조금만 늦게 불러냈어도 나랑 꼬맹이는 형체도 못 알아보게 박살 났겠지.`,JPN:`少しでも遅れていたら、私とガキは跡形もなくバラバラになっていただろうな。`,ENG:`Had I been a second later, me and the kid would have been smashed to bits.`,TWN:`再晚一點，我和小鬼就粉身碎骨了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`그 정도 높이에서 추락하면 어지간한 카운터도 살아남기 힘드니까.`,JPN:`あの高さから落ちたら、よほどのカウンターでなければ生き残れないだろうし。`,ENG:`Not even a Counter could survive a fall from that height.`,TWN:`因為在那個高度墜落，就算是制裁者也很難存活。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`내가 해 줄 수 있는 일은...... 그게 전부였어.`,JPN:`私にできることは……それがすべてだった。`,ENG:`And that... was all I could do for her.`,TWN:`我能做的……只有那些。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`하아...... 하아......`,JPN:`はあ……はあ……`,ENG:`*Pant* *Pant*`,TWN:`呼嗚……嗚嗚……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`윌버 씨가...... 그렇게 나쁜 사람일 줄은 몰랐어.`,JPN:`ウィルバーさんが……あんなに悪い人だったなんて。`,ENG:`I had no idea... Mr. Wilbur was such a bad person.`,TWN:`韋爾伯……我不知道原來他是這麼壞的人。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`언니 말을 들었더라면 이렇게 되지 않았을 텐데......`,JPN:`リタお姉ちゃんの言うことを聞いていればこんなことにならなかったのに……`,ENG:`Things wouldn't have come to this if I had just listened to Rita...`,TWN:`如果我聽姐姐的話，就不會變成這樣了……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`RITA_HORIZON_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`아냐! 정신 차리자, 대시!`,JPN:`違う！　しっかりしよう、ダッシュ！`,ENG:`No! I've got to pull myself together!`,TWN:`不，快打起精神來，黛西！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`여긴 대표님도 안 계셔. 너 혼자서라도 어떻게든 언니를 지켜 줘야 돼.`,JPN:`ここには代表もいない。私一人でリタお姉ちゃんを何としても守らないと。`,ENG:`The boss isn't even here. I've got to protect Rita by myself!`,TWN:`BOSS也不在。你自己一個人也一定要保護好姐姐。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`눈물 요정아, 달아나라! 뚝!`,JPN:`涙の妖精よ、飛んでけ！`,ENG:`Go away, tear fairy! Shoo!`,TWN:`眼淚啊，快飛的遠遠的！停！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`조금만 참아요, 언니. 제가 꼭 안전한 데까지 모셔다 드릴게요.`,JPN:`少しだけ我慢してください、リタお姉ちゃん。私が安全な場所まで運んであげますから。`,ENG:`Hang in there, Rita. I'll get you to safety, no matter what.`,TWN:`姐姐，你再忍一忍。我一定會把你帶到安全的地方。`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`쿨럭......! 쿨럭......!`,JPN:`ゲホッ……！　ゲホッ……！`,ENG:`*Cough!* *Cough!*`,TWN:`咳咳……！咳咳……！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`꼬, 꼬마야...... 너, 살아 있었구나......`,JPN:`お、お嬢ちゃん……生きていたのか……`,ENG:`K-kid... You're a-alive...`,TWN:`小、小鬼……你，還活著啊……`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`대장님?!`,JPN:`隊長！？`,ENG:`Captain?!`,TWN:`隊長？！`},stage:{bg:`COUNTERSIDE_PLAIN`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};